from jinja2 import Environment

env = Environment(extensions=['jinja2.ext.i18n'])

translations = {
    'Hello': 'Hallo',
}

def gettext(s):
    return translations.get(s, s)

def ngettext(s, p, n):
    return s if n == 1 else p

def dgettext(domain, s):
    return f'[{domain}] ' + translations.get(s, s)

def dngettext(domain, s, p, n):
    base = s if n == 1 else p
    return f'[{domain}] ' + base

env.install_gettext_callables(gettext, ngettext, newstyle=False, dgettext=dgettext, dngettext=dngettext)

tmpl = env.from_string('{% trans domain=\"admin\" %}Hello{% endtrans %}')
print(tmpl.render())

tmpl2 = env.from_string('{% trans %}Hello{% endtrans %}')
print(tmpl2.render())

tmpl3 = env.from_string('{% trans domain=\"admin\" count=3 %}{{ count }} item{% pluralize %}{{ count }} items{% endtrans %}')
print(tmpl3.render(count=3))
"
